const data = await res.json();
let reply = '', thinking = '';

if (preset.apiType === 'anthropic') {
  // Anthropic 原生格式
  for (const block of (data.content || [])) {
    if (block.type === 'thinking') thinking += (block.thinking || block.text || '');
    else if (block.type === 'text') reply += (block.text || '');
  }
} else {
  // === OpenAI 兼容格式 ===
  const msg = data.choices?.[0]?.message || {};
  reply = msg.content || '';

  // 读取思维链（reasoning_content）
  if (msg.reasoning_content) {
    thinking = msg.reasoning_content;
  }

  // 【修复气泡拉长】清除 content 中可能包裹的 <thinking> 标签
  reply = reply.replace(/<thinking>[\s\S]*?<\/thinking>/g, '').trim();
}

console.log('[Kel Debug] thinking length:', thinking.length, 'reply length:', reply.length);
if (thinking) console.log('[Kel Debug] thinking preview:', thinking.slice(0, 100));

// 【正则处理】调用 applyRegexRules，返回 { text, petState }
const regexResult = this.applyRegexRules(reply, 'output');
reply = regexResult.text;
const regexPetState = regexResult.petState; // 正则触发的 pet 状态，可能为 null

// ===== 按段落分割 =====
const paragraphs = reply.split(/\n\s*\n/).filter(p => p.trim().length > 0);
const finalParagraphs = paragraphs.length > 0 ? paragraphs : [reply];

